# smithery.ai exposes a public JSON catalog — fetch it to discover available MCP servers
import requests

def list_smithery_servers(query: str = "", limit: int = 20) -> list[dict]:
    resp = requests.get(
        "https://registry.smithery.ai/servers",
        params={"q": query, "pageSize": limit},
        timeout=10,
    )
    resp.raise_for_status()
    data = resp.json()
    return [
        {
            "name": s["qualifiedName"],
            "description": s.get("description", ""),
            "downloads": s.get("useCount", 0),
        }
        for s in data.get("servers", [])
    ]

results = list_smithery_servers("github")
for s in results[:5]:
    print(f'{s["downloads"]:>6}  {s["name"]:40s}  {s["description"][:60]}')

# Connect to an MCP server over stdio and convert its tools to Claude format
import subprocess, json, sys
from anthropic import Anthropic

client = Anthropic()

def start_mcp_server(command: list[str]) -> subprocess.Popen:
    return subprocess.Popen(
        command,
        stdin=subprocess.PIPE,
        stdout=subprocess.PIPE,
        stderr=subprocess.DEVNULL,
        text=True,
    )

def mcp_request(proc: subprocess.Popen, method: str, params: dict) -> dict:
    msg = json.dumps({"jsonrpc": "2.0", "id": 1, "method": method, "params": params})
    proc.stdin.write(msg + "\n")
    proc.stdin.flush()
    line = proc.stdout.readline()
    return json.loads(line).get("result", {})

def load_mcp_tools(proc: subprocess.Popen) -> list[dict]:
    result = mcp_request(proc, "tools/list", {})
    tools = []
    for tool in result.get("tools", []):
        tools.append({
            "name": tool["name"],
            "description": tool.get("description", ""),
            "input_schema": tool.get("inputSchema", {"type": "object", "properties": {}}),
        })
    return tools

def call_mcp_tool(proc: subprocess.Popen, name: str, args: dict) -> str:
    result = mcp_request(proc, "tools/call", {"name": name, "arguments": args})
    content = result.get("content", [])
    return "\n".join(c.get("text", "") for c in content if c.get("type") == "text")

