import anthropic, json

client = anthropic.Anthropic()

def run_agent_with_mcp(proc, user_message: str) -> str:
    tools = load_mcp_tools(proc)
    messages = [{"role": "user", "content": user_message}]

    while True:
        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            tools=tools,
            messages=messages,
        )

        if resp.stop_reason == "end_turn":
            return next(b.text for b in resp.content if hasattr(b, "text"))

        if resp.stop_reason != "tool_use":
            break

        tool_results = []
        for block in resp.content:
            if block.type != "tool_use":
                continue
            result_text = call_mcp_tool(proc, block.name, block.input)
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": result_text,
            })

        messages.append({"role": "assistant", "content": resp.content})
        messages.append({"role": "user", "content": tool_results})

import requests, yaml

def load_tools_from_openapi_url(spec_url: str, include_tags: list[str] | None = None) -> list[dict]:
    """
    Fetch an OpenAPI spec from a marketplace listing and convert operations to Claude tools.
    Many marketplaces (RapidAPI, APIs.guru) expose raw OpenAPI YAML/JSON at a stable URL.
    """
    resp = requests.get(spec_url, timeout=15)
    resp.raise_for_status()
    spec = yaml.safe_load(resp.text)

    tools = []
    for path, methods in spec.get("paths", {}).items():
        for method, op in methods.items():
            if method not in ("get", "post", "put", "patch", "delete"):
                continue
            tags = op.get("tags", [])
            if include_tags and not any(t in include_tags for t in tags):
                continue

            op_id = op.get("operationId", f"{method}_{path.replace('/','_')}")
            name = op_id.lower().replace("-", "_")[:64]
            props, required = {}, []

            for param in op.get("parameters", []):
                if param.get("in") in ("query", "path"):
                    pname = param["name"]
                    props[pname] = {
                        "type": param.get("schema", {}).get("type", "string"),
                        "description": param.get("description", ""),
                    }
                    if param.get("required"):
                        required.append(pname)

            tools.append({
                "name": name,
                "description": op.get("summary", op.get("description", name)),
                "input_schema": {
                    "type": "object",
                    "properties": props,
                    "required": required,
                },
            })
    return tools

