# Audit tool schema changes on upgrade:
import subprocess, json

def audit_schema_changes(old_tools: list[dict], new_tools: list[dict]) -> list[str]:
    """Return a list of breaking changes between two tool schema snapshots."""
    old_map = {t['name']: t for t in old_tools}
    new_map = {t['name']: t for t in new_tools}
    issues = []
    for name, old in old_map.items():
        if name not in new_map:
            issues.append(f'REMOVED: {name}')
            continue
        old_req = set(old.get('input_schema',{}).get('required',[]))
        new_req = set(new_map[name].get('input_schema',{}).get('required',[]))
        added = new_req - old_req
        if added:
            issues.append(f'NEW REQUIRED PARAMS in {name}: {added}')
    for name in new_map:
        if name not in old_map:
            issues.append(f'ADDED: {name} (safe)')
    return issues

# Test that your tool dispatch layer handles results from any source
import pytest
from unittest.mock import MagicMock, patch

class TestMultiSourceDispatch:

    def test_dispatches_mcp_tool(self):
        mock_proc = MagicMock()
        mock_proc.stdout.readline.return_value = json.dumps({
            "jsonrpc": "2.0", "id": 1, "result": {
                "content": [{"type": "text", "text": "PR list: ..."}]
            }
        })
        result = call_mcp_tool(mock_proc, "list_pull_requests", {"owner": "org", "repo": "api"})
        assert "PR list" in result

    def test_unique_tool_names_across_sources(self):
        mcp_tools = [{'name': 'github__list_prs', 'description': '...', 'input_schema': {}}]
        composio_tools = [{'name': 'slack__post_message', 'description': '...', 'input_schema': {}}]
        all_names = [t['name'] for t in mcp_tools + composio_tools]
        assert len(all_names) == len(set(all_names)), 'Duplicate tool names across sources'

    def test_unknown_tool_raises(self):
        with pytest.raises(ValueError, match='Unknown tool'):
            dispatch_tool_call('nonexistent_tool', {})
